#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int vis[N],n,q,f[N],fa[N],op[N],x[N],ans[N],cnt;
int find(int u)
{
	if(fa[u]==u) return u;
	return fa[u]=find(fa[u]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>q;
	for(int i=1;i<=n;i++)
	{
		fa[i]=i;
	}
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		f[v]=u;
	}
	vis[1]=1;
	for(int i=1;i<=q;i++) 
	{
		string s;
		cin>>s>>x[i];
		if(s=="Q")
		{
			op[i]=1;
		}
		else
		{
			op[i]=2;
			vis[x[i]]++;
		}
	}
	for(int i=1;i<=n;i++)
	{
//		cout<<i<<" "<<vis[i]<<"\n";
		if(!vis[i])
		{
//			cout<<i<<" "<<f[i]<<" "<<find(f[i])<<"\n";
			fa[i]=find(f[i]);
		}
	}
	for(int i=q;i>=1;i--)
	{
//		cout<<i<<" ::\n";
//		for(int j=1;j<=n;j++) cout<<fa[j]<<" ";
//		cout<<"\n";
		if(op[i]==1)
		{
			ans[++cnt]=find(x[i]);
		}
		else
		{
			vis[x[i]]--;
			if(vis[x[i]]==0) fa[x[i]]=find(f[x[i]]);
		}
	}
	for(int i=cnt;i>=1;i--) cout<<ans[i]<<'\n';
	return 0;
}
